import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  User, Shield, Mail, Trash2, Edit, Save, 
  X, Loader2, AlertCircle, Crown, Users 
} from 'lucide-react';

const Perfil = () => {
  const [perfil, setPerfil] = useState(null);
  const [usuarios, setUsuarios] = useState([]);
  const [loading, setLoading] = useState(true);
  const [editandoNome, setEditandoNome] = useState(false);
  const [novoNome, setNovoNome] = useState('');
  const [erroLocal, setErroLocal] = useState(null);

  useEffect(() => {
    carregarDados();
  }, []);

  const carregarDados = async () => {
    try {
      setLoading(true);
      const { data: { user } } = await supabase.auth.getUser();

      if (!user) {
        setErroLocal("Sessão expirada. Faça login novamente.");
        return;
      }

      const { data: meuPerfil, error: profileError } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', user.id)
        .maybeSingle();

      if (profileError) throw profileError;

      if (meuPerfil) {
        setPerfil(meuPerfil);
        setNovoNome(meuPerfil.nome || '');

        if (meuPerfil.tipo_usuario === 'proprietario') {
          const { data: lista } = await supabase
            .from('profiles')
            .select('*')
            .order('nome', { ascending: true });
          
          if (lista) setUsuarios(lista);
        }
      }
    } catch (err) {
      setErroLocal("Não foi possível carregar os dados.");
    } finally {
      setLoading(false);
    }
  };

  const atualizarNome = async () => {
    try {
      const { error } = await supabase
        .from('profiles')
        .update({ nome: novoNome })
        .eq('id', perfil.id);

      if (error) throw error;
      setPerfil({ ...perfil, nome: novoNome });
      setEditandoNome(false);
    } catch (err) {
      alert("Erro ao atualizar o nome.");
    }
  };

  const excluirUsuario = async (id, nome) => {
    if (id === perfil.id) return;
    
    if (window.confirm(`Excluir permanentemente o acesso de ${nome}?`)) {
      const { error } = await supabase.from('profiles').delete().eq('id', id);
      if (!error) {
        setUsuarios(usuarios.filter(u => u.id !== id));
      }
    }
  };

  if (loading) {
    return (
      <div style={containerCenter}>
        <Loader2 className="animate-spin" size={48} color="#4361ee" />
        <p style={{ color: '#64748b', fontWeight: 500 }}>Carregando seu universo...</p>
      </div>
    );
  }

  if (erroLocal || !perfil) {
    return (
      <div style={containerCenter}>
        <AlertCircle size={60} color="#ef4444" />
        <h3 style={{ color: '#0f172a', marginTop: '15px' }}>Ops! Algo deu errado</h3>
        <p style={{ color: '#64748b' }}>{erroLocal || "Perfil não localizado."}</p>
        <button onClick={() => window.location.reload()} style={btnPrimary}>Recarregar</button>
      </div>
    );
  }

  return (
    <div style={{ padding: '40px 20px', maxWidth: '900px', margin: '0 auto' }}>
      {/* Header com boas-vindas */}
      <header style={{ marginBottom: '40px' }}>
        <h1 style={titleStyle}>
          Olá, {perfil.nome.split(' ')[0]}! 👋
        </h1>
        <p style={{ color: '#64748b', fontSize: '1.1rem' }}>Gerencie suas informações e permissões de acesso.</p>
      </header>

      {/* Card Principal do Usuário */}
      <section style={mainCardStyle}>
        <div style={avatarCircle}>
          {perfil.tipo_usuario === 'proprietario' ? <Crown size={30} color="#fff" /> : <User size={30} color="#fff" />}
        </div>

        <div style={{ flex: 1 }}>
          <div style={{ marginBottom: '20px' }}>
            <label style={labelStyle}>Nome de Exibição</label>
            {editandoNome ? (
              <div style={editGroup}>
                <input 
                  value={novoNome} 
                  onChange={(e) => setNovoNome(e.target.value)}
                  style={inputStyle}
                  autoFocus
                />
                <button onClick={atualizarNome} style={iconBtnSave}><Save size={20}/></button>
                <button onClick={() => setEditandoNome(false)} style={iconBtnCancel}><X size={20}/></button>
              </div>
            ) : (
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                <h2 style={nameStyle}>{perfil.nome}</h2>
                <button onClick={() => setEditandoNome(true)} style={editBtn}><Edit size={16} /></button>
              </div>
            )}
          </div>

          <div style={infoGrid}>
            <div style={infoItem}>
              <label style={labelStyle}>E-mail</label>
              <div style={infoValue}><Mail size={16} /> {perfil.email}</div>
            </div>
            <div style={infoItem}>
              <label style={labelStyle}>Status da Conta</label>
              <div style={badgeStyle(perfil.tipo_usuario)}>
                <Shield size={14} /> {perfil.tipo_usuario}
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Área do Proprietário - Lista de Usuários */}
      {perfil.tipo_usuario === 'proprietario' && (
        <section style={{ marginTop: '50px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '25px' }}>
            <Users size={24} color="#0f172a" />
            <h3 style={{ fontSize: '1.4rem', fontWeight: 800, color: '#0f172a' }}>Membros do Sistema</h3>
          </div>

          <div style={{ display: 'grid', gap: '15px' }}>
            {usuarios.map(u => (
              <div key={u.id} style={userRowStyle}>
                <div style={smallAvatar}>{u.nome.charAt(0)}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 700, color: '#1e293b' }}>{u.nome}</div>
                  <div style={{ fontSize: '0.85rem', color: '#94a3b8' }}>{u.email}</div>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
                  <span style={badgeStyle(u.tipo_usuario)}>{u.tipo_usuario}</span>
                  {u.id !== perfil.id && (
                    <button onClick={() => excluirUsuario(u.id, u.nome)} style={deleteBtn}>
                      <Trash2 size={18} />
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </section>
      )}
    </div>
  );
};

// --- DESIGN SYSTEM ---
const containerCenter = { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '70vh', gap: '20px' };

const titleStyle = { fontSize: '2.4rem', fontWeight: 900, color: '#0f172a', marginBottom: '8px', letterSpacing: '-0.02em' };

const mainCardStyle = { 
  background: 'linear-gradient(135deg, #ffffff 0%, #f8fafc 100%)', 
  padding: '40px', 
  borderRadius: '32px', 
  boxShadow: '0 20px 25px -5px rgba(0,0,0,0.05), 0 10px 10px -5px rgba(0,0,0,0.02)', 
  border: '1px solid #ffffff',
  display: 'flex',
  gap: '30px',
  alignItems: 'center',
  flexWrap: 'wrap'
};

const avatarCircle = {
  width: '80px',
  height: '80px',
  borderRadius: '24px',
  background: 'linear-gradient(135deg, #4361ee 0%, #7209b7 100%)',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  boxShadow: '0 10px 15px -3px rgba(67, 97, 238, 0.3)'
};

const labelStyle = { fontSize: '0.75rem', fontWeight: 800, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: '8px', display: 'block' };

const nameStyle = { fontSize: '1.8rem', fontWeight: 800, color: '#0f172a', margin: 0 };

const infoGrid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px', marginTop: '20px' };

const infoItem = { background: '#fff', padding: '15px', borderRadius: '16px', border: '1px solid #f1f5f9' };

const infoValue = { display: 'flex', alignItems: 'center', gap: '8px', color: '#475569', fontWeight: 600, fontSize: '0.95rem' };

const inputStyle = { padding: '10px 16px', borderRadius: '12px', border: '2px solid #4361ee', fontSize: '1.1rem', outline: 'none', width: '100%', maxWidth: '300px' };

const editGroup = { display: 'flex', gap: '10px', alignItems: 'center' };

const iconBtnSave = { background: '#22c55e', color: '#fff', border: 'none', borderRadius: '12px', padding: '10px', cursor: 'pointer', transition: 'transform 0.2s' };

const iconBtnCancel = { background: '#f1f5f9', color: '#64748b', border: 'none', borderRadius: '12px', padding: '10px', cursor: 'pointer' };

const editBtn = { background: '#f1f5f9', color: '#4361ee', border: 'none', borderRadius: '10px', padding: '8px', cursor: 'pointer' };

const userRowStyle = { 
  display: 'flex', 
  alignItems: 'center', 
  padding: '18px 24px', 
  background: '#fff', 
  borderRadius: '20px', 
  border: '1px solid #f1f5f9',
  transition: 'all 0.2s ease',
  gap: '15px'
};

const smallAvatar = { width: '40px', height: '40px', borderRadius: '12px', background: '#e2e8f0', color: '#475569', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 800 };

const deleteBtn = { background: '#fef2f2', border: 'none', color: '#ef4444', borderRadius: '10px', padding: '10px', cursor: 'pointer' };

const btnPrimary = { background: '#4361ee', color: '#fff', border: 'none', padding: '14px 28px', borderRadius: '16px', fontWeight: 700, cursor: 'pointer', marginTop: '20px' };

const badgeStyle = (tipo) => ({
  display: 'inline-flex', 
  alignItems: 'center', 
  gap: '6px', 
  padding: '8px 14px', 
  borderRadius: '12px', 
  fontSize: '0.75rem', 
  fontWeight: 800,
  backgroundColor: tipo === 'proprietario' ? '#4361ee10' : '#f1f5f9',
  color: tipo === 'proprietario' ? '#4361ee' : '#64748b',
  textTransform: 'uppercase'
});

export default Perfil;
